import{_ as n,o as a,c as t,a2 as i}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Plugin external dependency resolution — automatic runtime dep hoisting on plugin add/remove","description":"","frontmatter":{"rfc":47,"title":"Plugin external dependency resolution — automatic runtime dep hoisting on plugin add/remove","status":"Draft","date":"July 2026","author":"kasunben","scope":"bin/sv.ts, runtime/package.json, runtime/generated/plugin-deps.json (new), scripts/dev.ts, docs/plugin-development.md; standalone, no prior RFC dependency\\n","incorporated_into_plan":"Yes — epic task 3.25 (plugins-runtime), non-prioritised roadmap slot."},"headers":[],"relativePath":"rfcs/0057-plugin-dep-hoisting.md","filePath":"rfcs/0057-plugin-dep-hoisting.md"}'),o={name:"rfcs/0057-plugin-dep-hoisting.md"};function s(d,e,l,r,p,c){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="rfc-0057-—-plugin-external-dependency-resolution" tabindex="-1">RFC 0057 — Plugin external dependency resolution <a class="header-anchor" href="#rfc-0057-—-plugin-external-dependency-resolution" aria-label="Permalink to &quot;RFC 0057 — Plugin external dependency resolution&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>When a plugin is added to a Sovereign instance, its external npm dependencies (anything that isn&#39;t a workspace package or a platform peer) must be resolvable by the Next.js compiler inside the runtime. Today that resolution fails silently unless someone manually adds the plugin&#39;s deps to <code>runtime/package.json</code> — a non-starter for third-party plugins and a DX landmine for first-party ones.</p><p>This RFC specifies that <code>sv plugin add</code> and <code>sv plugin remove</code> automatically maintain a <code>runtime/generated/plugin-deps.json</code> ledger and keep <code>runtime/package.json</code> in sync with the union of external deps across all installed plugins. The fix is transparent to plugin developers: they declare deps in their own <code>package.json</code> and the platform takes care of the rest.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Plugin source files are copied by the generate step into <code>runtime/app/(plugins)/&lt;id&gt;/</code> and compiled by Next.js as part of the runtime&#39;s module graph. Module resolution happens from the runtime&#39;s <code>node_modules</code> — not from the plugin&#39;s own directory. pnpm&#39;s strict isolation means a dep declared in <code>plugins/my-plugin/package.json</code> is installed in the plugin&#39;s own virtual store and is invisible to the runtime compiler.</p><p>The consequence today: every plugin that brings an external dependency (e.g. <code>@dnd-kit/core</code>, a charting library, a date library) silently breaks the runtime&#39;s typecheck and compilation unless someone manually adds those deps to <code>runtime/package.json</code>. This was discovered during Tasks plugin development when <code>@dnd-kit/*</code> had to be manually patched in.</p><p>This is untenable at scale:</p><ul><li>Third-party plugin developers have no way to trigger the patch.</li><li><code>sv plugin remove</code> has no corresponding cleanup path.</li><li>The coupling between a plugin&#39;s deps and the runtime&#39;s manifest is invisible and undocumented.</li></ul><h2 id="current-state" tabindex="-1">Current state <a class="header-anchor" href="#current-state" aria-label="Permalink to &quot;Current state&quot;">​</a></h2><ul><li><code>sv plugin add</code> clones/copies a plugin into <code>plugins/&lt;id&gt;/</code>, registers it, and runs <code>pnpm install</code> once. It does not inspect the plugin&#39;s <code>package.json</code> for external deps.</li><li><code>sv plugin remove</code> deletes the plugin directory and updates the registry. It does not clean up any deps.</li><li><code>runtime/package.json</code> is manually maintained. There is no record of which entries were added for which plugin.</li><li><code>plugins/*</code> are pnpm workspace members (via <code>plugins/*</code> glob in <code>pnpm-workspace.yaml</code>). Their deps are installed in the pnpm virtual store but are not hoisted to the runtime&#39;s resolution scope.</li><li>Local dev plugins (<code>plugins/*.local/</code>) follow the same model and have the same resolution gap.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="_1-plugin-dep-ledger-—-runtime-generated-plugin-deps-json" tabindex="-1">1. Plugin dep ledger — <code>runtime/generated/plugin-deps.json</code> <a class="header-anchor" href="#_1-plugin-dep-ledger-—-runtime-generated-plugin-deps-json" aria-label="Permalink to &quot;1. Plugin dep ledger — `runtime/generated/plugin-deps.json`&quot;">​</a></h3><p>A generated JSON file tracking which external deps each plugin contributed. Never hand-edited. Committed to the repo (it&#39;s a generated artefact, like <code>registry.ts</code>).</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;fs.sovereign.tasks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;@dnd-kit/core&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;^6.3.1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;@dnd-kit/sortable&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;^8.0.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;@dnd-kit/utilities&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;^3.2.2&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The ledger is the authoritative record of what <code>runtime/package.json</code> contains on behalf of plugins. It enables safe cleanup on remove: a dep is removed from <code>runtime/package.json</code> only when no remaining plugin entry in the ledger references it.</p><h3 id="_2-dep-extraction-—-what-counts-as-an-external-dep" tabindex="-1">2. Dep extraction — what counts as an external dep <a class="header-anchor" href="#_2-dep-extraction-—-what-counts-as-an-external-dep" aria-label="Permalink to &quot;2. Dep extraction — what counts as an external dep&quot;">​</a></h3><p>When reading a plugin&#39;s <code>package.json</code>, filter out:</p><ul><li><code>@sovereignfs/*</code> — workspace packages, already resolved via pnpm workspaces.</li><li>Platform peer deps already in <code>runtime/package.json</code>: <code>next</code>, <code>react</code>, <code>react-dom</code>, <code>typescript</code>, <code>react-dom</code>, and any other explicit platform dep.</li><li><code>devDependencies</code> — never needed at runtime.</li></ul><p>Everything remaining in <code>dependencies</code> is an <strong>external dep</strong> that must be hoisted to the runtime.</p><h3 id="_3-sv-plugin-add-—-install-path" tabindex="-1">3. <code>sv plugin add</code> — install path <a class="header-anchor" href="#_3-sv-plugin-add-—-install-path" aria-label="Permalink to &quot;3. `sv plugin add` — install path&quot;">​</a></h3><p>After the plugin directory is created and the registry is regenerated:</p><ol><li>Read <code>plugins/&lt;id&gt;/package.json</code>.</li><li>Extract external deps (step 2 filter).</li><li>If non-empty: a. Write/update <code>runtime/generated/plugin-deps.json</code> with the plugin&#39;s entry. b. Add the deps to <code>runtime/package.json</code> <code>dependencies</code> (merge, not replace — preserve existing entries from other plugins). c. Run <code>pnpm install --filter runtime</code> to install the new deps.</li><li>Print a summary: <code>Added 3 runtime deps for fs.sovereign.tasks</code>.</li></ol><p>If the plugin declares no external deps, skip silently.</p><h3 id="_4-sv-plugin-remove-—-cleanup-path" tabindex="-1">4. <code>sv plugin remove</code> — cleanup path <a class="header-anchor" href="#_4-sv-plugin-remove-—-cleanup-path" aria-label="Permalink to &quot;4. `sv plugin remove` — cleanup path&quot;">​</a></h3><p>After the plugin directory and registry entry are removed:</p><ol><li>Read <code>runtime/generated/plugin-deps.json</code>.</li><li>Find the departing plugin&#39;s dep set.</li><li>Compute the union of all <em>remaining</em> plugins&#39; dep sets.</li><li>Remove from <code>runtime/package.json</code> any dep that is in the departing set but <strong>not</strong> in the remaining union (i.e. no other plugin still needs it).</li><li>Update <code>runtime/generated/plugin-deps.json</code> (delete the plugin&#39;s entry).</li><li>Run <code>pnpm install --filter runtime</code> to prune the removed deps.</li><li>Print a summary: <code>Removed 2 runtime deps (1 still needed by another plugin, kept)</code>.</li></ol><h3 id="_5-local-dev-plugins-—-pnpm-dev-sync" tabindex="-1">5. Local dev plugins — <code>pnpm dev</code> sync <a class="header-anchor" href="#_5-local-dev-plugins-—-pnpm-dev-sync" aria-label="Permalink to &quot;5. Local dev plugins — `pnpm dev` sync&quot;">​</a></h3><p>For <code>.local</code> plugins the add/remove path isn&#39;t always used. <code>scripts/dev.ts</code> should run a lightweight sync at startup:</p><ol><li>Scan <code>plugins/*.local/</code> for <code>package.json</code> files.</li><li>For each, extract external deps.</li><li>Compare against <code>runtime/generated/plugin-deps.json</code>.</li><li>If there is a diff (new dep or removed dep), update the ledger and <code>runtime/package.json</code>, then run <code>pnpm install --filter runtime</code>.</li><li>Print a one-line notice if deps changed; continue dev startup as normal.</li></ol><p>This makes <code>pnpm dev</code> self-healing for local plugins — adding a dependency to a local plugin&#39;s <code>package.json</code> is picked up automatically on the next <code>pnpm dev</code>.</p><h3 id="_6-version-conflict-policy" tabindex="-1">6. Version conflict policy <a class="header-anchor" href="#_6-version-conflict-policy" aria-label="Permalink to &quot;6. Version conflict policy&quot;">​</a></h3><p>If a plugin declares <code>&quot;some-lib&quot;: &quot;^2.0.0&quot;</code> and another plugin already contributed <code>&quot;some-lib&quot;: &quot;^1.0.0&quot;</code> to the runtime, the newer version wins and the ledger records both contributors. On remove, the dep stays at the remaining plugin&#39;s version. A warning is printed when a version conflict is detected at install time so the operator is aware.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><h3 id="do-nothing-document-the-manual-step" tabindex="-1">Do nothing / document the manual step <a class="header-anchor" href="#do-nothing-document-the-manual-step" aria-label="Permalink to &quot;Do nothing / document the manual step&quot;">​</a></h3><p>Rejected. Third-party plugin developers cannot update <code>runtime/package.json</code> on an installed instance. The manual step is invisible and fails at runtime, not at install time.</p><h3 id="require-plugins-to-declare-platform-peers-only" tabindex="-1">Require plugins to declare platform peers only <a class="header-anchor" href="#require-plugins-to-declare-platform-peers-only" aria-label="Permalink to &quot;Require plugins to declare platform peers only&quot;">​</a></h3><p>Rejected. Plugins are mini-applications and will legitimately need domain libraries (date pickers, chart libs, drag-and-drop). Prohibiting external deps would severely limit what plugins can build.</p><h3 id="change-the-compilation-model-longer-term-path" tabindex="-1">Change the compilation model (longer-term path) <a class="header-anchor" href="#change-the-compilation-model-longer-term-path" aria-label="Permalink to &quot;Change the compilation model (longer-term path)&quot;">​</a></h3><p>Instead of copying plugin source into the runtime, build each plugin as a compiled package (via <code>tsup</code>) and have the runtime import it. This lets pnpm resolve the plugin&#39;s deps from the plugin&#39;s own <code>node_modules</code> naturally — no hoisting needed. This is the right long-term architecture but requires significant changes to the generate step and the way Next.js loads plugin routes.</p><p>This RFC is the interim fix; the compilation model change is the eventual successor. Both can coexist: the ledger approach works whether source is copied or imported.</p><h3 id="use-pnpm-shamefully-hoist" tabindex="-1">Use <code>pnpm --shamefully-hoist</code> <a class="header-anchor" href="#use-pnpm-shamefully-hoist" aria-label="Permalink to &quot;Use `pnpm --shamefully-hoist`&quot;">​</a></h3><p>Rejected. Shamefully hoisting all workspace deps defeats the purpose of pnpm&#39;s strict isolation and can cause hard-to-diagnose version conflicts across unrelated packages.</p><h3 id="add-each-plugin-as-a-direct-dep-of-the-runtime-workspace" tabindex="-1">Add each plugin as a direct dep of the runtime (<code>workspace:*</code>) <a class="header-anchor" href="#add-each-plugin-as-a-direct-dep-of-the-runtime-workspace" aria-label="Permalink to &quot;Add each plugin as a direct dep of the runtime (`workspace:*`)&quot;">​</a></h3><p>Adding <code>&quot;@sovereignfs/sovereign-tasks&quot;: &quot;workspace:*&quot;</code> to <code>runtime/package.json</code> makes pnpm link the plugin and transitively install its deps. But it still requires <code>runtime/package.json</code> to list every installed plugin, which is the same coupling problem — just at the package level instead of the dep level. It also doesn&#39;t work for third-party plugins whose package names aren&#39;t <code>@sovereignfs/*</code>.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li>Should the ledger file be committed or gitignored? Committing it makes review transparent (you can see what a new plugin adds). Gitignoring it means it&#39;s always regenerated. Leaning toward committed.</li><li>Should version conflict warnings be blocking (error + exit) or advisory? Advisory seems right — SemVer ranges often resolve safely.</li><li>Should <code>sv plugin migrate</code> (the DB migration command from the same sprint) and this dep-hoisting step be combined into a single <code>sv plugin sync</code> command that brings a plugin fully up to date after a manifest or schema change?</li><li>Does the dev-startup sync in <code>scripts/dev.ts</code> add too much latency? If <code>pnpm install</code> is triggered on every <code>pnpm dev</code> even when nothing changed, it should be gated on a hash/mtime check of the plugin <code>package.json</code>.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li><strong>RFC draft:</strong> agree on ledger format, filter rules, and the dev-startup sync.</li><li><strong>Implementation:</strong> update <code>sv plugin add</code>, <code>sv plugin remove</code>, and <code>scripts/dev.ts</code>. Generate initial <code>plugin-deps.json</code> from the current <code>runtime/package.json</code> entries that are known to be plugin-contributed (<code>@dnd-kit/*</code> from Tasks).</li><li><strong>Remove manual workaround:</strong> delete <code>@dnd-kit/*</code> from <code>runtime/package.json</code> and let the ledger manage them.</li><li><strong>Docs:</strong> update <code>docs/plugin-development.md</code> — external deps are declared in the plugin&#39;s own <code>package.json</code> and the platform installs them; no manual step needed.</li></ol><p>No published package (<code>@sovereignfs/sdk</code>, <code>@sovereignfs/ui</code>) or manifest schema changes are required.</p><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>July 2026</td><td>Initial draft</td></tr></tbody></table>',52)])])}const g=n(o,[["render",s]]);export{u as __pageData,g as default};
